const fs = require('fs');
const loan = JSON.parse(fs.readFileSync('sample_inputs/loan_008.json', 'utf8'));

function computeLoanMetrics(loan) {
  const principal = loan.principal;
  const annualRatePct = loan.annual_rate_pct;
  const termMonths = loan.term_months;
  const originationFee = loan.origination_fee;

  const monthlyRate = annualRatePct / 100 / 12;

  let monthlyPayment;
  if (monthlyRate === 0) {
    monthlyPayment = principal / termMonths;
  } else {
    const numerator = monthlyRate * Math.pow(1 + monthlyRate, termMonths);
    const denominator = Math.pow(1 + monthlyRate, termMonths) - 1;
    monthlyPayment = principal * numerator / denominator;
  }

  monthlyPayment = Math.round(monthlyPayment * 100) / 100;
  const totalInterest = Math.round((monthlyPayment * termMonths - principal) * 100) / 100;
  const totalPaid = Math.round((principal + totalInterest + originationFee) * 100) / 100;

  const discrepancies = [];

  if (monthlyPayment !== loan.stated_monthly_payment) {
    discrepancies.push({
      field: 'monthly_payment',
      stated: loan.stated_monthly_payment,
      computed: monthlyPayment,
      delta: Math.round((monthlyPayment - loan.stated_monthly_payment) * 100) / 100
    });
  }

  if (totalInterest !== loan.stated_total_interest) {
    discrepancies.push({
      field: 'total_interest',
      stated: loan.stated_total_interest,
      computed: totalInterest,
      delta: Math.round((totalInterest - loan.stated_total_interest) * 100) / 100
    });
  }

  if (totalPaid !== loan.stated_total_paid) {
    discrepancies.push({
      field: 'total_paid',
      stated: loan.stated_total_paid,
      computed: totalPaid,
      delta: Math.round((totalPaid - loan.stated_total_paid) * 100) / 100
    });
  }

  return {
    loan_id: loan.loan_id,
    lender: loan.lender,
    computed: {
      monthly_payment: monthlyPayment,
      total_interest: totalInterest,
      total_paid: totalPaid
    },
    discrepancies: discrepancies,
    valid: discrepancies.length === 0
  };
}

const result = computeLoanMetrics(loan);
fs.writeFileSync('output.json', JSON.stringify(result, null, 2));
console.log(JSON.stringify(result, null, 2));
